local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxCrossRankMatchCtrl:LxBaseCtrl
local LxCrossRankMatchCtrl = classX("LxCrossRankMatchCtrl", LxBaseCtrl)

function LxCrossRankMatchCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxCrossRankMatchCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end



function LxCrossRankMatchCtrl:CheckShowNewSeasonId()
    local info = ModuleCenter.CrossRankMatch:GetCrossRankMatchInfo()
    if not info then return end

    if not info:IsStartMatch() then return end

    local seasonId = info.seasonId
    if not seasonId or seasonId < 1 then return end

    if seasonId - 1 == 0 then return end

    local endTime = info.endTime
    local recordCGMEndTime = checknumber(LxPlayerPrefs.RecordCGMEndTime) or 0
    if recordCGMEndTime < endTime then
        HandlerCenter.CrossRankMatch:CrossRankBalanceInfoReq()
        return true
    end
end

function LxCrossRankMatchCtrl:SetRecordCGMEndTime()
    local info = ModuleCenter.CrossRankMatch:GetCrossRankMatchInfo()
    if not info then return false end

    LxPlayerPrefs.RecordCGMEndTime = info.endTime
end

---@return V_CrossGradingIntervalRef[]
function LxCrossRankMatchCtrl:GetCrossGradingIntervalRefList()
    if not self._initCrossGradingIntervalRefList then
        ---@type V_CrossGradingIntervalRef[]
        local list = {}
        for k,v in pairs(GameTable.CrossWarIntervalRef) do
            table.insert(list,v)
        end
        table.sort(list,function(a,b) return a.sort < b.sort end)
        self._initCrossGradingIntervalRefList = list
    end
    return self._initCrossGradingIntervalRefList
end

---@return V_CrossGradingIntervalRef
function LxCrossRankMatchCtrl:GetCrossGradingRefByScore(score)
    local ref
    local initRefs = self:GetCrossGradingIntervalRefList()
    local firstRef = initRefs[1]
    if firstRef.scoreDown <= score and firstRef.scoreUp >= score then
        ref = firstRef
    else
        local lastRef = initRefs[#initRefs]
        if lastRef.scoreDown <= score then
            ref = lastRef
        else
            for i,v in ipairs(initRefs) do
                if v.scoreDown <= score and v.scoreUp >= score then
                    ref = v
                    break
                end
            end
        end
    end
    if not ref then
        if LOG_ERROR_ENABLED then
            printError("段位赛:","未找到积分：" .. score .. " 对应的段位配置")
        end
        ref = firstRef
    end
    return ref
end

function LxCrossRankMatchCtrl:GetCrossGradingCombatAwards()
    if not self._initCrossGradingCombatAwards then
        local list = {}
        local finishCond
        for k,v in pairs(GameTable.CrossWarAwardRef) do
            finishCond = v.finishCond
            table.insert(list,{
                refId = k,
                sort = v.sort,
                finishCond = finishCond,
                rewards = LxDataHelper.ParseItemStrList(v.reward),

                title = string.replace(I18nText(8519),finishCond),
                rewardType = 1,
            })
        end
        table.sort(list,function(a,b) return a.sort < b.sort end)
        self._initCrossGradingCombatAwards = list
    end
    return self._initCrossGradingCombatAwards
end

function LxCrossRankMatchCtrl:GetCrossGradingIntervalRewards()
    if not self._initCrossGradingIntervalRewards then
        local list = {}
        local name
        local initRefs = self:GetCrossGradingIntervalRefList()
        for i,v in ipairs(initRefs) do
            name = I18nText(v.name)
            table.insert(list,{
                refId = v.refId,
                name = name,
                nameColor = v.nameColor,
                rewards = LxDataHelper.ParseItemStrList(v.reward),

                title = string.replace(I18nText(8518),name),
                rewardType = 2,
            })
        end
        self._initCrossGradingIntervalRewards = list
    end
    return self._initCrossGradingIntervalRewards
end

--- 界面打开后，提示段位升级
function LxCrossRankMatchCtrl:CheckIsNeedOpenGradingUp()
    local needOpen,oldRefId,newRefId = ModuleCenter.CrossRankMatch:CheckIsNewRankGrading()
    if needOpen then
        ShowPanel(UiNames.CrossRankGradingUpTips,{
            oldRefId = oldRefId,
            newRefId = newRefId,
        })
    end
end


return LxCrossRankMatchCtrl